// 1. '0 0 * * * *'         → every hour (at 0 seconds, 0 minutes past each hour)
// 2. '0 0 9 * * MON-FRI'  → 9:00 AM on weekdays
// 3. '0 0/30 * * * *'     → every 30 minutes (at 0 and 30 past each hour)
// 4. '0 0 0 1 * *'         → midnight on the 1st of every month
// 5. '0 0 18 * * FRI'      → 6:00 PM every Friday

public class CronExplanations {
    public static void main(String[] args) {
        System.out.println("1: Every hour");
        System.out.println("2: 9:00 AM weekdays");
        System.out.println("3: Every 30 minutes");
        System.out.println("4: Midnight on 1st of month");
        System.out.println("5: 6PM every Friday");
    }
}

import java.util.concurrent.*;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

@Service
public class ReportService {

    @Async
    public CompletableFuture<String> generateReport(String userId) {
        try { Thread.sleep(2000); }  // simulate long generation
        catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        String report = "Report for user: " + userId + " generated at " + java.time.LocalDateTime.now();
        return CompletableFuture.completedFuture(report);
    }
}

// How a caller uses it:
class CallerExample {
    void example(ReportService reportService) throws Exception {
        // Starts async, returns immediately:
        CompletableFuture<String> future = reportService.generateReport("U01");
        System.out.println("Request submitted, doing other work...");

        // Wait up to 10s for the result:
        String report = future.get(10, TimeUnit.SECONDS);
        System.out.println(report);
    }
}

