import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;

// NotificationService:
@Service
class NotificationService {
    @Async
    public void sendEmail(String orderId, String userEmail) {
        System.out.printf("[%s] Sending email for %s to %s%n",
            Thread.currentThread().getName(), orderId, userEmail);
        try { Thread.sleep(1500); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        System.out.println("Email sent for " + orderId);
    }
}

// OrderController:
@RestController @RequestMapping("/api/orders")
class OrderController {
    private final NotificationService notificationSvc;
    OrderController(NotificationService n) { notificationSvc = n; }

    @PostMapping
    public ResponseEntity<String> placeOrder(@RequestBody java.util.Map<String,String> req) {
        String orderId = "ORD-" + java.util.UUID.randomUUID().toString().substring(0,8);
        System.out.printf("[%s] Order %s saved%n", Thread.currentThread().getName(), orderId);

        notificationSvc.sendEmail(orderId, req.getOrDefault("email","user@example.com"));
        // Email will arrive later — HTTP thread already gone

        System.out.printf("[%s] Returning 201 immediately%n", Thread.currentThread().getName());
        return ResponseEntity.status(201).body(orderId);
    }
}

