import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

// ========== ANTI-PATTERN (self-invocation — @Async IGNORED) ==========
@Service
class OrderServiceBad {
    // @Async on THIS class's method:
    @Async
    public void sendEmailAsync(String orderId) {
        System.out.println("Sending email for " + orderId);  // runs SYNCHRONOUSLY!
    }

    public String placeOrder(String symbol) {
        String id = "ORD-001";
        this.sendEmailAsync(id);  // ANTI-PATTERN: 'this.' bypasses Spring proxy!
        // ^ Still runs synchronously despite @Async!
        return id;
    }
}

// ========== CORRECT FIX (separate bean — @Async WORKS) ==========
@Service
class EmailService {
    @Async
    public void sendEmail(String orderId) {
        System.out.printf("[%s] Sending email for %s%n",
            Thread.currentThread().getName(), orderId);  // runs ASYNCHRONOUSLY!
    }
}

@Service
class OrderServiceGood {
    private final EmailService emailService;  // INJECTED — separate bean
    OrderServiceGood(EmailService e) { emailService = e; }

    public String placeOrder(String symbol) {
        String id = "ORD-001";
        emailService.sendEmail(id);  // CORRECT: via proxy → @Async works!
        return id;
    }
}

