import java.util.concurrent.CompletableFuture;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import java.util.*;

record PortfolioSummary(List<String> stocks, List<String> funds, List<String> bonds) {}

@Service class StockService     { @Async public CompletableFuture<List<String>> fetchPrices(String uid)  { return CompletableFuture.completedFuture(List.of("TCS","RELIANCE")); } }
@Service class MutualFundService{ @Async public CompletableFuture<List<String>> fetchFunds(String uid)   { return CompletableFuture.completedFuture(List.of("HDFC Fund")); } }
@Service class BondService      { @Async public CompletableFuture<List<String>> fetchBonds(String uid)   { return CompletableFuture.completedFuture(List.of("GOI Bond 2030")); } }

@Service
public class DataAggregatorService {
    private final StockService stockSvc;
    private final MutualFundService fundSvc;
    private final BondService bondSvc;

    DataAggregatorService(StockService s, MutualFundService f, BondService b) {
        stockSvc=s; fundSvc=f; bondSvc=b;
    }

    public PortfolioSummary aggregatePortfolio(String userId) throws Exception {
        // Launch all three in parallel:
        CompletableFuture<List<String>> stocksFuture = stockSvc.fetchPrices(userId);
        CompletableFuture<List<String>> fundsFuture  = fundSvc.fetchFunds(userId);
        CompletableFuture<List<String>> bondsFuture  = bondSvc.fetchBonds(userId);

        // Wait for all:
        CompletableFuture.allOf(stocksFuture, fundsFuture, bondsFuture).join();

        return new PortfolioSummary(
            stocksFuture.get(), fundsFuture.get(), bondsFuture.get());
    }
}

