import org.springframework.aop.interceptor.AsyncUncaughtExceptionHandler;
import org.springframework.scheduling.annotation.AsyncConfigurer;
import org.springframework.scheduling.annotation.EnableAsync;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import java.lang.reflect.Method;
import java.util.*;

// Custom exception handler:
class LoggingAsyncExceptionHandler implements AsyncUncaughtExceptionHandler {
    List<String> caughtErrors = new ArrayList<>();
    @Override
    public void handleUncaughtException(Throwable ex, Method method, Object... params) {
        String msg = String.format("Async error in %s: %s", method.getName(), ex.getMessage());
        System.err.println(msg);
        caughtErrors.add(msg);
    }
}

// Register in AsyncConfigurer:
@Configuration @EnableAsync
class AsyncExceptionConfig implements AsyncConfigurer {
    static LoggingAsyncExceptionHandler handler = new LoggingAsyncExceptionHandler();
    @Override
    public AsyncUncaughtExceptionHandler getAsyncUncaughtExceptionHandler() { return handler; }
}

